package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsNullStringSet_NullNullString() throws Exception {
        // Use DEFAULT which has nullString == null
        CSVFormat format = CSVFormat.DEFAULT;
        // isNullStringSet should return false
        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_NonNullNullString() throws Exception {
        // Create a CSVFormat with non-null nullString using withNullString
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        // isNullStringSet should return true
        assertTrue(format.isNullStringSet());
    }

}
